'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
assertions.push({ name: 'normalize_ok', ok: !!$json.intent && !!$json.content_type && !!$json.capture_text });
return [{ json: { ...$json, smoke_assertions: assertions } }];

'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
const action = String($json.action || '').trim();
const actionOk = action === 'inserted' || action === 'updated' || action === 'skipped';
const entryIdOk = action === 'skipped' ? true : !!$json.entry_id;
assertions.push({ name: 'insert_action_valid', ok: actionOk, action });
assertions.push({ name: 'entry_id_present', ok: entryIdOk, entry_id: $json.entry_id ?? null });
return [{ json: { ...$json, smoke_assertions: assertions } }];

'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
const hasUrl = !!($json.url || $json.url_canonical);
const ok = !hasUrl || !!($json.clean_text || $json.extracted_text || $json.capture_text);
assertions.push({ name: 'web_extraction_path_ok', ok, has_url: hasUrl });
return [{ json: { ...$json, smoke_assertions: assertions } }];

'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
const ok = !$json.error;
assertions.push({ name: 'tier1_ok', ok });
return [{ json: { ...$json, smoke_assertions: assertions } }];

'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
const msg = String($json.telegram_message || '');
assertions.push({ name: 'format_message_non_empty', ok: msg.length > 0 });
return [{ json: { ...$json, smoke_assertions: assertions } }];

'use strict';

