const msg = String($json.telegram_message || '');
assertions.push({ name: 'format_thought_non_empty', ok: msg.length > 0 });
return [{ json: { ...$json, smoke_assertions: assertions } }];

'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
const msg = String($json.telegram_message || '');
assertions.push({ name: 'telegram_send_message_present', ok: msg.length > 0 });
const telegramMessageId = $json.message_id ?? ($json.result && $json.result.message_id) ?? null;
if (telegramMessageId != null) {
  assertions.push({ name: 'telegram_message_id_present', ok: true });
}
const ok = assertions.every((a) => a.ok === true);
return [{
  json: {
    ...$json,
    test_case: 'telegram_capture',
    ok,
    run_id: $json.test_run_id || null,
    artifacts: {
      entry_id: $json.entry_id ?? null,
      action: $json.action ?? null,
      telegram_message: msg || null,
      telegram_message_id: telegramMessageId,
    },
    assertions,
    error: ok ? null : { message: 'telegram capture assertions failed' },
  },
}];

'use strict';

const text = String($json.raw_text || ($json.message && ($json.message.text || $json.message.caption)) || '').trim();
const URL_RE = /(https?:\/\/[^\s<>()]+|www\.[^\s<>()]+)/ig;
const matches = text.match(URL_RE) || [];
const urls = matches.map((u) => {
  let v = String(u || '').trim();
  while (/[)\],.?!:;"'»]+$/.test(v)) v = v.replace(/[)\],.?!:;"'»]+$/, '');
  if (/^www\./i.test(v)) v = `https://${v}`;
  return v;
}).filter(Boolean);

const residue = text
  .replace(URL_RE, ' ')
  .replace(/[\s,;|\u2022()\[\]{}<>0-9.\-_:]+/g, '')
  .trim();

let mode = 'thought';
let mode_error = null;
if (urls.length > 0) {
  if (residue.length > 0) {
    mode = 'invalid_mixed';
    mode_error = 'mixed_telegram_capture_not_supported';
  } else {
    mode = 'url';
  }
}

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
assertions.push({ name: 'telegram_mode_routed', ok: true, mode, url_count: urls.length });

return [{
  json: {
    ...$json,
    raw_text: text,
    telegram_capture_mode: mode,
    telegram_url_count: urls.length,
    telegram_urls: urls,
    telegram_mode_error: mode_error,
    smoke_assertions: assertions,
  },
}];

'use strict';

const results = Array.isArray($json.results) ? $json.results : [];
const base = { ...$json };

return results
  .filter((r) => {
    const action = String((r && r.action) || '');
    const ok = r && r.ok === true;
    const hasId = !!(r && r.id);
    const hasUrl = !!(r && (r.url || r.url_canonical));
    return ok && (action === 'inserted' || action === 'updated') && hasId && hasUrl;
  })
  .map((r) => ({
    json: {
      ...base,
      id: r.id,
      entry_id: r.entry_id ?? null,
      url: r.url || r.url_canonical || null,
      url_canonical: r.url_canonical || r.url || null,
      content_type: 'newsletter',
      bulk_web_extraction: true,
    },
  }));

'use strict';

const { mdv2Message } = require('@igasovic/n8n-blocks/shared/telegram-markdown.js');

const total = Number($json.url_count || 0);
const inserted = Number($json.inserted_count || 0);
const updated = Number($json.updated_count || 0);
const skipped = Number($json.skipped_count || 0);
const failed = Number($json.failed_count || 0);
const results = Array.isArray($json.results) ? $json.results : [];

const successEntries = results
  .filter((r) => r && r.ok === true && (r.action === 'inserted' || r.action === 'updated') && r.entry_id != null)
  .map((r) => String(r.entry_id));
const failedRows = results.filter((r) => r && (r.ok === false || r.action === 'failed'));

const lines = [
  `URL batch processed: ${total}`,
  `Inserted: ${inserted} Updated: ${updated} Skipped: ${skipped} Failed: ${failed}`,
];

if (successEntries.length > 0) {
  lines.push(`Entry IDs: ${successEntries.slice(0, 20).join(', ')}`);
}

if (failedRows.length > 0) {
  const errs = failedRows
    .slice(0, 5)
    .map((r) => `#${Number(r.batch_index) + 1}: ${String(r.error || 'failed')}`)
    .join(' | ');
  lines.push(`Errors: ${errs}`);
}

return [{ json: { ...$json, telegram_message: mdv2Message(lines.join('\n')) } }];

'use strict';

const { mdv2Message } = require('@igasovic/n8n-blocks/shared/telegram-markdown.js');

const items = $input.all().map((i) => i.json || {});
if (!items.length) return [];

const base = items[0];
const total = Number(base.url_count || 0);
const inserted = Number(base.inserted_count || 0);
const updated = Number(base.updated_count || 0);
const skipped = Number(base.skipped_count || 0);
const failed = Number(base.failed_count || 0);

const extractionSuccess = items.filter((i) => i && i.id).length;
const attempted = inserted + updated;
const extractionFailed = Math.max(0, attempted - extractionSuccess);

const lines = [
  `URL batch processed: ${total}`,
  `Inserted: ${inserted} Updated: ${updated} Skipped: ${skipped} Failed: ${failed}`,
  `Extraction attempted: ${attempted} Succeeded: ${extractionSuccess} Failed: ${extractionFailed}`,
];

const entryIds = items
  .map((i) => i.entry_id)
  .filter((v) => v != null)
  .map((v) => String(v));
if (entryIds.length > 0) {
  lines.push(`Extracted entry IDs: ${entryIds.slice(0, 20).join(', ')}`);
}

return [{ json: { ...base, telegram_message: mdv2Message(lines.join('\n')) } }];

